import UIKit

// Define allowed hosts and paths for universal links
let allowedHosts = ["myapp.com"]
let allowedPaths = ["/reset-password"]

class UniversalLinkHandler {
    static func handleUniversalLink(url: URL) -> Bool {
        guard let scheme = url.scheme, scheme == "https" else { return false }
        
        // Validate host and path against allowlist
        if !allowedHosts.contains(where: { $0 == url.host }) || !allowedPaths.contains(where: { $0 == url.path }) {
